template:
{% set footer_name = app_name or frappe.db.get_single_value('Website Settings', 'app_name') or 'Pikt, Inc.' %}
{% set footer_logo = app_logo or frappe.db.get_single_value('Website Settings', 'app_logo') %}
{% set footer_year = frappe.utils.now_datetime().year %}
<style>
.pikt-footer {
  margin-top: 4rem;
  border-top: 1px solid rgba(17, 24, 39, 0.08);
  background: linear-gradient(180deg, #fbfaf8 0%, #f4efe6 100%);
}
.pikt-footer__wrap {
  padding: 2rem 0;
}
.pikt-footer__brand {
  display: inline-flex;
  align-items: center;
  gap: 0.9rem;
  color: #1f2937;
  text-decoration: none;
}
.pikt-footer__brand:hover,
.pikt-footer__brand:focus {
  color: #111827;
  text-decoration: none;
}
.pikt-footer__logo {
  max-height: 42px;
  width: auto;
  display: block;
}
.pikt-footer__name {
  font-size: 1rem;
  font-weight: 600;
  letter-spacing: 0.02em;
}
.pikt-footer__tagline {
  font-size: 0.82rem;
  color: #6b7280;
}
.pikt-footer__meta {
  color: #4b5563;
  font-size: 0.9rem;
}
@media (max-width: 767.98px) {
  .pikt-footer__meta {
    margin-top: 1rem;
    text-align: left;
  }
}
</style>
<footer class="web-footer pikt-footer">
  <div class="container pikt-footer__wrap">
    <div class="row align-items-center">
      <div class="col-md-7 col-12">
        <a class="pikt-footer__brand" href="/" aria-label="{{ footer_name }} home">
          {% if footer_logo %}
            <img class="pikt-footer__logo" src="{{ footer_logo }}" alt="{{ footer_name }} logo">
          {% endif %}
          <span>
            <span class="pikt-footer__name">{{ footer_name }}</span>
            <span class="pikt-footer__tagline d-block">Customer portal and account access.</span>
          </span>
        </a>
      </div>
      <div class="col-md-5 col-12 text-md-right pikt-footer__meta">
        <div>&copy; {{ footer_year }} {{ footer_name }}</div>
        <div>All rights reserved.</div>
      </div>
    </div>
  </div>
</footer>
